import React from 'react';
import styled from 'styled-components';
import { Link } from 'react-router-dom';
import { useTheme } from '../context/ThemeContext';

const HeroSection = styled.section`
  position: relative;
  display: flex;
  justify-content: center;
  align-items: center;
  padding: 0;
  color: white;
  width: 100%;
  min-height: 90vh;
  box-sizing: border-box;
  overflow: hidden;
  background: blur(0px);
`;

const HeroBg = styled.div`
  position: absolute;
  top: 0; left: 0; right: 0; bottom: 0;
  z-index: 1;

  &::before {
    content: "";
    position: absolute;
    top: 0; left: 0; right: 0; bottom: 0;
    // background: url("${require('../assets/3334896.jpg')}") no-repeat center center / cover;
    opacity: ${props => props.isDarkTheme ? 0.5 : 0.3};
    z-index: -1;
    transition: opacity 0.3s ease;
  }
`;

const HeroContent = styled.div`
  backdrop-filter: blur(4px);
  -webkit-backdrop-filter: blur(20px);
  background-color: ${props => props.isDarkTheme 
    ? 'rgba(0, 0, 0, 0.4)' 
    : 'rgba(255, 255, 255, 0.2)'};
  position: relative;
  z-index: 2;
  padding: 10% 0;
  width: 100%;
  height: 100%;
  text-align: center;
  animation: zoomOut 1s ease-in backwards;
`;

const Title = styled.h1`
  font-size: 5.5rem;
  margin-bottom: 0;
  line-height: 1.2;
  color: transparent;
  -webkit-text-stroke: 1px ${props => props.isDarkTheme ? 'white' : '#000'};
  font-weight: bold;

  @media (max-width: 768px) {
    font-size: 2.5rem;
  }
`;

const Highlight = styled.span`
  font-size: 4.5rem;
  margin-bottom: 20px;
  line-height: 1.2;
  font-weight: 1000;
  background: linear-gradient(to right, #00FFFF, #00BFFF);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  position: relative;
  display: inline-block;

  &::after {
    content: '';
    position: absolute;
    bottom: -5px;
    left: 0;
    width: 100%;
    height: 2px;
    background: linear-gradient(to right, #00FFFF, #00BFFF);
    transform: scaleX(0);
    transform-origin: center;
    transition: transform 0.5s ease;
  }

  ${HeroContent}:hover &::after {
    transform: scaleX(1);
  }
`;

const Description = styled.p`
  font-size: 1.3rem;
  margin-bottom: 30px;
  line-height: 1.6;
  color: rgba(255, 255, 255, 0.9);
`;

const ButtonContainer = styled.div`
  display: flex;
  text-align: center;
  justify-content: center;
  gap: 20px;
`;

const StyledButton = styled(Link)`
  text-decoration: none;
  color: ${props => props.isDarkTheme ? 'rgb(59, 0, 87)' : '#fff'};
  background: ${props => props.isDarkTheme 
    ? 'linear-gradient(45deg, #00BFFF, #00FFFF)'
    : 'linear-gradient(45deg, #008B8B, #006666)'};
  padding: 10px 25px;
  border-radius: 30px;
  font-size: 20px;
  font-weight: bold;
  transition: all 0.3s ease;
  position: relative;
  overflow: hidden;
  z-index: 1;

  &::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: ${props => props.isDarkTheme 
      ? 'linear-gradient(45deg, #00FFFF, #00BFFF)'
      : 'linear-gradient(45deg, #006666, #008B8B)'};
    z-index: -1;
    transition: opacity 0.3s ease;
    opacity: 0;
  }

  &:hover {
    transform: translateY(-3px);
    box-shadow: ${props => props.isDarkTheme 
      ? '0 10px 20px rgba(0, 191, 255, 0.3)'
      : '0 10px 20px rgba(0, 139, 139, 0.3)'};
  }

  &:hover::before {
    opacity: 1;
  }
`;

const Hero = () => {
  const { theme, isDarkTheme } = useTheme();

  return (
    <HeroSection theme={theme}>
      <HeroBg isDarkTheme={isDarkTheme}>
        <HeroContent 
          data-aos="fade-right" 
          data-aos-duration="1000"
          isDarkTheme={isDarkTheme}
        >
          <Title isDarkTheme={isDarkTheme}>Welcome to <br /></Title>
          <Highlight>Optimus</Highlight>
          <Description>
            Empowering innovation through workshops, hackathons, and a tech-driven community. 
            Join us in shaping the future of technology.
          </Description>
          <ButtonContainer>
            <StyledButton 
              to="https://github.com/optimusorgz" 
              target="_blank"
              data-aos="zoom-in" 
              data-aos-delay="300"
              isDarkTheme={isDarkTheme}
            >
              Join Now
            </StyledButton>
            <StyledButton 
              to="/events"
              data-aos="zoom-in" 
              data-aos-delay="400"
              isDarkTheme={isDarkTheme}
            >
              Explore Events
            </StyledButton>
          </ButtonContainer>
        </HeroContent>
      </HeroBg>
    </HeroSection>
  );
};

export default Hero;
